interface HarnessContext {
}

async function evaluate(draft: string, context: HarnessContext): Promise<{valid: boolean, feedback: string[]}> {
    const feedback: string[] = [];
    let valid = true;

    if (!draft || draft.trim().length === 0) {
        feedback.push("Draft cannot be empty.");
        valid = false;
    }

    if (draft.length < 20) {
        feedback.push("Draft is too short. Please elaborate more.");
        valid = false;
    }

    const requiredKeyword = "adventure";
    if (!draft.toLowerCase().includes(requiredKeyword)) {
        feedback.push(`Draft should include the keyword "${requiredKeyword}" to align with the narrative theme.`);
        valid = false;
    }

    if (feedback.length === 0) {
        valid = true;
    } else {
        valid = false;
    }

    return { valid, feedback };
}

