    let valid = true;

    if (!draft || draft.trim().length === 0) {
        feedback.push("Draft cannot be empty.");
        valid = false;
    }

    if (draft.length < 20) {
        feedback.push("Draft is too short. Please elaborate more.");
        valid = false;
    }

    // The previous keyword check for "adventure" has been removed.
    // The example "Elaria drew her Sunblade and faced Ignis." is a valid narrative start
    // even without explicitly using the word "adventure".
    // The narrative theme is considered broader than requiring this specific keyword.

    if (feedback.length === 0) {
        valid = true;
    } else {
        valid = false;
    }

    return { valid, feedback };
}
